A debounce function delays calling fn until wait milliseconds have passed since the last invocation, preventing rapid repeated calls (e.g., on scroll or input).

```javascript
function debounce(fn, wait) {
  let timeout;
  return function (...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => fn.apply(context, args), wait);
  };
}

// Example: only call save() 300ms after the user stops typing
const save = (value) => console.log('Saving', value);
const debouncedSave = debounce(save, 300);

document.querySelector('#input').addEventListener('input', (e) => {
  debouncedSave(e.target.value);
});
```
